CREATE TABLE "PersonalAccessToken" ( "id" TEXT NOT NULL, "token" TEXT NOT NULL, "userId" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "expiresAt" TIMESTAMP(3), CONSTRAINT "PersonalAccessToken_pkey" PRIMARY KEY ("id") ); CREATE UNIQUE INDEX "PersonalAccessToken_token_key" ON "PersonalAccessToken"("token"); CREATE INDEX "PersonalAccessToken_userId_idx" ON "PersonalAccessToken"("userId"); ALTER TABLE "PersonalAccessToken" ADD CONSTRAINT "PersonalAccessToken_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE;
